const addPoint = () => {
// 最常用的手机号验证正则
const MOBILE_REGEX = /^(?:(?:\+|00)86)?1[3-9]\d{9}$/;

// 验证是否为手机号码
function isValidMobile(phone) {
  return MOBILE_REGEX.test(phone.trim());
}

const { pkid, burning_location, burning_time, approved_area, fire_reason, approved_fire_time, longitude, latitude, phone_number, on_site_manager } = global.airGlobalVariables.currentPointInfo;
if (!(burning_location && burning_time && approved_area && fire_reason && approved_fire_time && longitude && latitude)) {
  ElementPlus.ElMessage.error('请检查必填项');
  return false;
}

if (!isValidMobile(global.airGlobalVariables.currentPointInfo.phone_number) && phone_number) {
  ElementPlus.ElMessage.error('手机号码格式错误');
  return false;
}

const url = '/waterevaluate/burn/add';
const token = localStorage.getItem('token');

axios.post(
  url,
  {
    pkid, burning_location, burning_time, approved_area, fire_reason, approved_fire_time, longitude, latitude, phone_number, on_site_manager,
    region_code: global.regionaQuery.regionCode,
  },
  {
    baseURL: global.businessServiceBaseUrl,
    headers: {
      'usertoken': token,
      'token': token,
      'Content-Type': 'application/json'
    }
  }
).then((res) => {
  if (res?.data?.code === 200) {
    // 创建点位成功后通知地图和炼山审批面板 重新加载数据
    rootData.rootSocket.emit(
      'message',  // 固定的消息名称，不能修改
      {
        room: global.socketRoom,  // 房间号，一般使用全局变量socketRoom
        type: 'createPointSuccess',  // 消息类型名称
        data: {}
      }
    );

    // 关闭创建点位弹窗
    rootData.rootSocket.emit(
      'message',  // 固定的消息名称，不能修改
      {
        room: global.socketRoom,  // 房间号，一般使用全局变量socketRoom
        type: 'closeDialog',  // 消息类型名称
        data: {}
      }
    );
  }
}).catch(error => {
  console.error('创建点位失败:', error);
});
};
